using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through the MEAI abstraction ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Define tools ---
var notepad = new ResearchNotepad();
AITool[] tools =
[
    AIFunctionFactory.Create(
        (string query) => WebSearchTool.SearchAsync(query),
        "web_search",
        "Searches the web for the given query and returns a list of result snippets."),
    AIFunctionFactory.Create(
        ([Description("The note text to save")] string note) => notepad.AddNote(note),
        "save_note",
        "Saves a research note for later use in the summary."),
    AIFunctionFactory.Create(
        () => notepad.GetNotes(),
        "get_notes",
        "Retrieves all saved research notes."),
];

// --- Create the agent ---
var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "An AI research assistant that searches the web and takes notes.",
    instructions: """
        You are a research assistant. When given a topic:
        1. Search the web for relevant information using the web_search tool (make 2-3 searches with different queries).
        2. Save important findings as notes using the save_note tool.
        3. After researching, retrieve your notes with get_notes.
        4. Provide a well-structured summary of your findings with key points and sources.
        Be thorough but concise.
        """,
    tools: tools);

// --- Run the agent ---
Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine();

if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching: {topic}\n");

var session = await agent.CreateSessionAsync();
var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a summary: {topic}",
    session,
    runOptions))
{
    Console.Write(update.Text);
}

Console.WriteLine("\n\n=== Research Complete ===");

// --- Tool implementations ---

/// <summary>Simulated web search tool that fetches real-looking results for demonstration.</summary>
static class WebSearchTool
{
    private static readonly HttpClient s_http = new();

    public static async Task<string> SearchAsync(string query)
    {
        Console.WriteLine($"  [🔍 Searching: \"{query}\"]");

        try
        {
            // Use Wikipedia's API as a free, no-key search proxy
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch={encoded}&srlimit=3&format=json";
            var json = await s_http.GetStringAsync(url);

            // Parse with System.Text.Json
            using var doc = System.Text.Json.JsonDocument.Parse(json);
            var results = doc.RootElement
                .GetProperty("query")
                .GetProperty("search");

            var sb = new StringBuilder();
            sb.AppendLine($"Search results for \"{query}\":");

            foreach (var item in results.EnumerateArray())
            {
                var title = item.GetProperty("title").GetString();
                var snippet = StripHtml(item.GetProperty("snippet").GetString() ?? "");
                sb.AppendLine($"- {title}: {snippet}");
                sb.AppendLine($"  Source: https://en.wikipedia.org/wiki/{Uri.EscapeDataString(title ?? "")}");
            }

            return sb.ToString();
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static string StripHtml(string html) =>
        System.Text.RegularExpressions.Regex.Replace(html, "<.*?>", "");
}

/// <summary>Simple in-memory notepad for the agent to store findings.</summary>
sealed class ResearchNotepad
{
    private readonly List<string> _notes = [];

    public string AddNote(string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [📝 Note saved ({_notes.Count} total)]");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        sb.AppendLine($"Research notes ({_notes.Count}):");
        for (int i = 0; i < _notes.Count; i++)
            sb.AppendLine($"{i + 1}. {_notes[i]}");
        return sb.ToString();
    }
}

